awl:
workflow "AutoNotify" {
  trigger: webhook "order.created";
  condition: order.total >= 500000 -> "premium";
  send: zalo_zns "{{customer.phone}}";
  wait: 7200s;
  send: zalo_zns "delivery_update";
  log: "order notification complete";
}

workflow "InventorySync" {
  trigger: webhook "order.completed";
  execute: deduct_inventory;
  condition: stock < 10 -> "low_stock_alert";
  send: email "{{manager.email}}";
  log: "inventory synced";
}
